import{_ as t,o,c as a,ae as i}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Create Links With Ivy (New)","description":"","frontmatter":{"title":"Create Links With Ivy (New)","slug":"create-links-with-ivy-new"},"headers":[],"relativePath":"marketer-hub/create-links-with-ivy-new.md","filePath":"marketer-hub/create-links-with-ivy-new.md"}'),n={name:"marketer-hub/create-links-with-ivy-new.md"};function s(r,e,l,p,h,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<p>You can use Ivy, Branch&#39;s AI, to create Short Links in Branch.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Check your link before you publish it. AI can make mistakes.</p></div><p>Complete the following steps to start creating a link with Ivy:</p><ol><li>In Branch, select <strong>Campaigns</strong> &gt; <strong>Links.</strong></li><li>Select the <strong>Create</strong> button.</li><li>Select <strong>Short Link</strong>. The <strong>Create Link</strong> page will open.</li><li>Enter your prompt in the <strong>Ask Ivy</strong> text box at the top of the page.</li></ol><h2 id="prompt-components" tabindex="-1">Prompt components <a class="header-anchor" href="#prompt-components" aria-label="Permalink to &quot;Prompt components&quot;">​</a></h2><p>An Ivy prompt is a natural-language instruction that tells Branch what kind of link to create. The most effective prompts include the following components:</p><ul><li><strong>Campaign and channel</strong>: The campaign the link is for and the channel the user is originating from (e.g., email, SMS, push notification, Facebook).</li><li><strong>Objective</strong>: The goal of the link, such as engagement, acquisition, or conversion.</li><li><strong>Destination</strong>: Where app users should land (define the in-app path) and where non-app users should go (define a URL or specify app store redirect).</li><li><strong>Extras</strong>: Any additional settings such as coupon codes, custom field values, content metadata, platform-specific routing, or social media previews.</li></ul><p>Not every prompt needs all four components. If there are no extras, you can leave that part out. However, always include a campaign, channel, objective, and at least one destination.</p><h2 id="write-effective-prompts" tabindex="-1">Write effective prompts <a class="header-anchor" href="#write-effective-prompts" aria-label="Permalink to &quot;Write effective prompts&quot;">​</a></h2><p>Use the following guidelines to help you write prompts that give Ivy the information it needs to build the right link:</p><ul><li><strong>Be specific and descriptive</strong>: Ivy works best when you are specific about the type of link you want to create. Include the campaign name, the channel, and exact destination paths rather than vague terms like &quot;homepage&quot; or &quot;the website.&quot;</li><li><strong>Define destinations explicitly</strong>: Always specify where app users should land and where non-app users should go. Use exact paths for in-app destinations (e.g., /products/winter-jacket) and full URLs for web fallbacks (e.g., <a href="https://example.com/products/winter-jacket" target="_blank" rel="noreferrer">https://example.com/products/winter-jacket</a>). If you want non-app users redirected to download the app, say so directly.</li><li><strong>State your objective</strong>: Tell Ivy what the link should achieve. For example, start with &quot;Create a conversion link…&quot; or &quot;Create an engagement link…&quot; so Ivy can configure the link correctly for your goal.</li><li><strong>Include extras when they apply</strong>: If your campaign uses coupon codes, custom fields, or content metadata, include them in the prompt. Ivy will apply them to the link configuration. If you leave them out, they won&#39;t be added.</li><li><strong>Tell Ivy what you don&#39;t want</strong>: Ivy uses your past links to help create your new links. This means it may include data options and tags from previous links. If you don&#39;t want a specific tag that you know you&#39;ve used, tell Ivy to exclude it in your prompt.</li></ul><h2 id="good-prompts-vs-bad-prompts" tabindex="-1">Good prompts vs. bad prompts <a class="header-anchor" href="#good-prompts-vs-bad-prompts" aria-label="Permalink to &quot;Good prompts vs. bad prompts&quot;">​</a></h2><p>The following examples compare vague prompts with prompts that give Ivy the right level of detail. Use these as a reference when writing your own prompts.</p><h4 id="fall-campaign" tabindex="-1">Fall campaign <a class="header-anchor" href="#fall-campaign" aria-label="Permalink to &quot;Fall campaign&quot;">​</a></h4><p><strong>Bad prompt</strong>: &quot;Create a link for our Fall 2026 campaign and coupon on Facebook. Send app users to /shop/items. Non-app users to the website.&quot;</p><ul><li>Leaves out the coupon code, so Ivy won&#39;t apply it.</li><li>Uses a vague fallback (&quot;the website&quot;) without specifying the URL.</li><li>Doesn&#39;t include an objective for the campaign.</li></ul><p><strong>Good prompt</strong>: &quot;Create a conversion link for our Fall 2026 campaign on Facebook. App users should be sent to /shop/items. Non-app users should go to <a href="https://monster-site.github.io/shop/items.html" target="_blank" rel="noreferrer">https://monster-site.github.io/shop/items.html</a>. 10OFF is the coupon code.&quot;</p><ul><li>Campaign and channel: Fall 2026, Facebook</li><li>Objective: Conversion</li><li>Destination: /shop/items and full web URL</li><li>Extras: Coupon code (10OFF)</li></ul><h4 id="winter-collection" tabindex="-1">Winter collection <a class="header-anchor" href="#winter-collection" aria-label="Permalink to &quot;Winter collection&quot;">​</a></h4><p><strong>Bad prompt</strong>: &quot;Make a link for our Winter Collection that takes people to their profile.&quot;</p><ul><li>Doesn&#39;t state the channel — is this link for a push notification, SMS, or a social site?</li><li>No clear destination defined.</li><li>Doesn&#39;t include an objective for the campaign.</li></ul><p><strong>Good prompt</strong>: &quot;Make a push notification link for an engagement campaign about our Winter Collection. Send users to /collections/winter profile page to select their favorite colors.&quot;</p><ul><li>Campaign and channel: Winter Collection, Push Notification</li><li>Objective: Engagement</li><li>Destination: /collections/winter</li></ul><h4 id="sms-flash-sale" tabindex="-1">SMS flash sale <a class="header-anchor" href="#sms-flash-sale" aria-label="Permalink to &quot;SMS flash sale&quot;">​</a></h4><p><strong>Bad prompt</strong>: &quot;Spin up links for the DXR promo and push it through SMS.&quot;</p><ul><li>Uses internal shorthand (&quot;DXR promo&quot;) that Ivy can&#39;t interpret.</li><li>Doesn&#39;t specify what the campaign is about or who it targets.</li></ul><p><strong>Good prompt</strong>: &quot;I&#39;m running a 24-hour flash sale via SMS. iOS users should deep link to /sales/flash-sale, Android users to /promotion/flash-sale. Others go to the app store.&quot;</p><ul><li>Campaign and channel: 24-hour flash sale, SMS</li><li>Objective: Conversion (flash sale)</li><li>Destination: iOS /sales/flash-sale, Android /promotion/flash-sale, others to app store</li></ul><h2 id="refine-your-prompts" tabindex="-1">Refine your prompts <a class="header-anchor" href="#refine-your-prompts" aria-label="Permalink to &quot;Refine your prompts&quot;">​</a></h2><p>If Ivy&#39;s output doesn&#39;t match what you need, you can refine your prompt or follow up with additional instructions.</p><p><strong>Add detail</strong>: If the result is missing something, add more information to your prompt. For example, instead of saying &quot;Send users to the rewards page,&quot; specify the platform behavior: &quot;App users should go to the rewards page, desktop users to the weekly deals page.&quot;</p><p><strong>Use follow-up prompts</strong>: After Ivy creates a link, you can ask follow-up questions or make adjustments. For example:</p><ul><li>&quot;Show me the analytics tags you applied.&quot;</li><li>&quot;Change the fallback URL to <a href="https://example.com/sale." target="_blank" rel="noreferrer">https://example.com/sale.</a>&quot;</li><li>&quot;Add coupon code SAVE20 to this link.&quot;</li></ul><h2 id="common-mistakes" tabindex="-1">Common mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common mistakes&quot;">​</a></h2><p>Avoid the following mistakes when writing Ivy prompts:</p><ul><li><strong>Using vague destinations</strong>: Terms like &quot;homepage&quot; or &quot;the website&quot; don&#39;t tell Ivy whether you mean an in-app screen or a web URL. Always specify the full path or URL.</li><li><strong>Omitting the channel</strong>: Ivy needs to know where the link will be shared (email, SMS, push, social) to configure it correctly.</li><li><strong>Leaving out the objective</strong>: Without an objective, Ivy can&#39;t determine whether the link is meant for engagement, acquisition, or conversion.</li><li><strong>Using internal shorthand or jargon</strong>: Ivy can&#39;t interpret abbreviations or project codenames that aren&#39;t part of your Branch configuration. Use plain, descriptive language.</li><li><strong>Forgetting platform-specific needs</strong>: If your link needs to behave differently on iOS, Android, or desktop, mention each platform and its destination explicitly.</li></ul><h2 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h2><ul><li><strong>Use simple, action-based language</strong>: Start your prompt with what you want Ivy to do, such as &quot;Create a QR code for an in-store sign&quot; or &quot;Create a conversion link for our Spring campaign.&quot;</li><li><strong>Lean on templates</strong>: Ivy can reference existing templates to stay aligned with your team&#39;s ideal link setup. If your team uses a standard configuration, mention it in your prompt.</li><li><strong>Always test your links</strong>: Even with Ivy&#39;s automation, review the link&#39;s routing, fallbacks, and analytics tags before publishing.</li><li><strong>Share prompts with your team</strong>: Ivy makes link creation accessible to teammates of all skill levels. Sharing example prompts helps maintain consistency and data quality across your organization.</li></ul>',38)])])}const d=t(n,[["render",s]]);export{m as __pageData,d as default};
